import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import { SmsNotificationAdapter } from '../../src/adapters/sms.adapter.js';
import { WebhookNotificationAdapter } from '../../src/adapters/webhook.adapter.js';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { NotificationHistoryService, resetLogIdCounter } from '../../src/services/notification-history.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

/**
 * Integration tests for the full notification pipeline:
 * EventBus → NotificationService → Adapters (email/SMS/webhook) → Preferences → History
 *
 * These tests wire up all real components (no mocks) and verify end-to-end behavior.
 */
describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let emailAdapter: EmailNotificationAdapter;
  let smsAdapter: SmsNotificationAdapter;
  let webhookAdapter: WebhookNotificationAdapter;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();

    emailAdapter = new EmailNotificationAdapter({ from: 'noreply@taskflow.com' });
    smsAdapter = new SmsNotificationAdapter({ fromNumber: '+15551234567' });
    webhookAdapter = new WebhookNotificationAdapter({ url: 'https://hooks.example.com/notify' });

    const prefRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(prefRepo);

    const logRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(logRepo);

    notificationService = new NotificationService(
      eventBus,
      [emailAdapter, smsAdapter, webhookAdapter],
      preferencesService,
      historyService,
    );

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetLogIdCounter();
  });

  // -- Helpers --

  function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    };
  }

  function makeOrderStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
    return {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
      ...overrides,
    };
  }

  // -----------------------------------------------------------------------
  // 1. Email notification end-to-end
  // -----------------------------------------------------------------------
  describe('email channel end-to-end', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      // Default preferences have email enabled — send via event
      await eventBus.emit(makeOrderCreatedEvent());

      // Notification stored in service
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.channel).toBe('email');
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.recipient).toBe('alice@example.com');

      // Email adapter received the message
      const emails = emailAdapter.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('noreply@taskflow.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');

      // History service recorded it
      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.recipient).toBe('alice@example.com');
    });

    it('should use email templates for formatting', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emails = emailAdapter.getSentEmails();
      // Template wraps subject with "Order Confirmation —"
      expect(emails[0]?.subject).toContain('Order Confirmation');
      // Template wraps body with greeting
      expect(emails[0]?.body).toContain('Dear Customer');
      expect(emails[0]?.body).toContain('Thank you for your order');
    });
  });

  // -----------------------------------------------------------------------
  // 2. SMS notification end-to-end
  // -----------------------------------------------------------------------
  describe('SMS channel end-to-end', () => {
    it('should deliver SMS notification when SMS preferences are enabled', async () => {
      const result = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Order Placed',
        body: 'Your order has been placed.',
        channel: 'sms',
      });

      expect(result).not.toBeNull();
      expect(result!.channel).toBe('sms');
      expect(result!.status).toBe('sent');

      // SMS adapter received the message
      const messages = smsAdapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15559876543');
      expect(messages[0]?.from).toBe('+15551234567');

      // History recorded
      const logs = historyService.getByRecipient('+15559876543');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.channel).toBe('sms');
    });

    it('should truncate long SMS messages', async () => {
      const longBody = 'A'.repeat(200);

      await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Alert',
        body: longBody,
        channel: 'sms',
      });

      const messages = smsAdapter.getSentMessages();
      expect(messages[0]?.body.length).toBeLessThanOrEqual(160);
      expect(messages[0]?.body).toMatch(/\.\.\.$/);
    });
  });

  // -----------------------------------------------------------------------
  // 3. Webhook notification end-to-end
  // -----------------------------------------------------------------------
  describe('webhook channel end-to-end', () => {
    it('should deliver webhook notification', async () => {
      const result = await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'webhook-consumer-1',
        subject: 'System Alert',
        body: 'CPU usage exceeded threshold.',
        channel: 'webhook',
      });

      expect(result).not.toBeNull();
      expect(result!.channel).toBe('webhook');
      expect(result!.status).toBe('sent');

      // Webhook adapter recorded the call
      const webhooks = webhookAdapter.getSentWebhooks();
      expect(webhooks).toHaveLength(1);
      expect(webhooks[0]?.url).toBe('https://hooks.example.com/notify');
      expect(webhooks[0]?.payload.type).toBe('system_alert');
      expect(webhooks[0]?.payload.body).toBe('CPU usage exceeded threshold.');
      expect(webhooks[0]?.headers['Content-Type']).toBe('application/json');

      // History recorded
      const logs = historyService.query({ channel: 'webhook' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
    });
  });

  // -----------------------------------------------------------------------
  // 4. History logging
  // -----------------------------------------------------------------------
  describe('notification history', () => {
    it('should log all notifications across channels in history', async () => {
      // Send one notification per channel
      await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Order confirmed',
        channel: 'email',
      });
      await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Order',
        body: 'Order confirmed',
        channel: 'sms',
      });
      await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'webhook-consumer',
        subject: 'Order',
        body: 'Order confirmed',
        channel: 'webhook',
      });

      expect(historyService.getCount()).toBe(3);

      // Query by channel
      expect(historyService.query({ channel: 'email' })).toHaveLength(1);
      expect(historyService.query({ channel: 'sms' })).toHaveLength(1);
      expect(historyService.query({ channel: 'webhook' })).toHaveLength(1);
    });

    it('should persist history even after clearing in-memory notifications', async () => {
      await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Alert',
        body: 'Test',
        channel: 'email',
      });

      notificationService.clearNotifications();
      expect(notificationService.getNotificationCount()).toBe(0);

      // History survives clear
      expect(historyService.getCount()).toBe(1);
      expect(historyService.getAll()[0]?.recipient).toBe('alice@example.com');
    });

    it('should record failed notifications in history', async () => {
      // Send email with invalid recipient — adapter returns failure
      const result = await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'not-an-email',
        subject: 'Alert',
        body: 'Test',
        channel: 'email',
      });

      expect(result!.status).toBe('failed');

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toContain('Invalid recipient email');
    });

    it('should support querying history by type', async () => {
      await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Confirmed',
        channel: 'email',
      });
      await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Alert',
        body: 'Alert!',
        channel: 'email',
      });

      expect(historyService.getByType('order_confirmation')).toHaveLength(1);
      expect(historyService.getByType('system_alert')).toHaveLength(1);
    });
  });

  // -----------------------------------------------------------------------
  // 5. Preferences enforcement
  // -----------------------------------------------------------------------
  describe('user preferences enforcement', () => {
    it('should suppress email when email channel is disabled', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false } },
      });

      const result = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Your order',
        channel: 'email',
      });

      expect(result).toBeNull();
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(historyService.getCount()).toBe(0);
    });

    it('should suppress SMS when SMS channel is disabled', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { sms: { enabled: false } },
      });

      const result = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Order',
        body: 'Your order',
        channel: 'sms',
      });

      expect(result).toBeNull();
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(historyService.getCount()).toBe(0);
    });

    it('should suppress webhook when webhook channel is disabled', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { webhook: { enabled: false } },
      });

      const result = await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'consumer',
        subject: 'Alert',
        body: 'Alert',
        channel: 'webhook',
      });

      expect(result).toBeNull();
      expect(webhookAdapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should respect per-category preferences across all channels', async () => {
      preferencesService.updatePreferences('user-1', {
        categoryPreferences: [
          { category: 'order_confirmation', enabled: false },
          { category: 'order_status_update', enabled: true },
          { category: 'welcome', enabled: true },
          { category: 'account_update', enabled: true },
          { category: 'system_alert', enabled: true },
        ],
      });

      // order_confirmation suppressed on email
      const emailResult = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Your order',
        channel: 'email',
      });
      expect(emailResult).toBeNull();

      // order_confirmation suppressed on SMS too
      const smsResult = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Order',
        body: 'Your order',
        channel: 'sms',
      });
      expect(smsResult).toBeNull();

      // system_alert still works on all channels
      const alertResult = await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Alert',
        body: 'Alert!',
        channel: 'email',
      });
      expect(alertResult).not.toBeNull();
    });

    it('should allow one channel while suppressing another for the same user', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false }, sms: { enabled: true } },
      });

      const emailResult = await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Alert',
        body: 'Alert',
        channel: 'email',
      });
      const smsResult = await notificationService.sendNotification({
        type: 'system_alert',
        userId: 'user-1',
        recipient: '+15559876543',
        subject: 'Alert',
        body: 'Alert',
        channel: 'sms',
      });

      expect(emailResult).toBeNull();
      expect(smsResult).not.toBeNull();
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
    });

    it('should not check preferences when no userId is provided', async () => {
      // Disable all channels for user-1
      preferencesService.updatePreferences('user-1', {
        channelPreferences: {
          email: { enabled: false },
          sms: { enabled: false },
          webhook: { enabled: false },
        },
      });

      // System notification without userId — should bypass preference checks
      const result = await notificationService.sendNotification({
        type: 'system_alert',
        recipient: 'admin@example.com',
        subject: 'Alert',
        body: 'System alert',
        channel: 'email',
      });

      expect(result).not.toBeNull();
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
    });
  });

  // -----------------------------------------------------------------------
  // 6. Notification ordering
  // -----------------------------------------------------------------------
  describe('notification ordering across pipeline', () => {
    it('should deliver notifications in FIFO order', async () => {
      const results = [];
      for (let i = 1; i <= 5; i++) {
        const result = await notificationService.sendNotification({
          type: 'system_alert',
          userId: 'user-1',
          recipient: 'alice@example.com',
          subject: `Alert ${i}`,
          body: `Body ${i}`,
          channel: 'email',
        });
        results.push(result);
      }

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(5);

      // Verify sequential ordering
      for (let i = 0; i < 5; i++) {
        expect(notifications[i]?.subject).toBe(`Alert ${i + 1}`);
      }

      // History should also be in order
      const logs = historyService.getAll();
      expect(logs).toHaveLength(5);
      for (let i = 0; i < 5; i++) {
        expect(logs[i]?.notificationId).toBe(notifications[i]?.id);
      }
    });

    it('should maintain order for concurrent sends across channels', async () => {
      // Fire all three concurrently
      const [emailResult, smsResult, webhookResult] = await Promise.all([
        notificationService.sendNotification({
          type: 'system_alert',
          userId: 'user-1',
          recipient: 'alice@example.com',
          subject: 'Email Alert',
          body: 'Via email',
          channel: 'email',
        }),
        notificationService.sendNotification({
          type: 'system_alert',
          userId: 'user-1',
          recipient: '+15559876543',
          subject: 'SMS Alert',
          body: 'Via SMS',
          channel: 'sms',
        }),
        notificationService.sendNotification({
          type: 'system_alert',
          userId: 'user-1',
          recipient: 'webhook-consumer',
          subject: 'Webhook Alert',
          body: 'Via webhook',
          channel: 'webhook',
        }),
      ]);

      expect(emailResult).not.toBeNull();
      expect(smsResult).not.toBeNull();
      expect(webhookResult).not.toBeNull();

      // Notifications should be in submission order
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(3);
      expect(notifications[0]?.channel).toBe('email');
      expect(notifications[1]?.channel).toBe('sms');
      expect(notifications[2]?.channel).toBe('webhook');

      // History in same order
      const logs = historyService.getAll();
      expect(logs).toHaveLength(3);
      expect(logs[0]?.channel).toBe('email');
      expect(logs[1]?.channel).toBe('sms');
      expect(logs[2]?.channel).toBe('webhook');
    });
  });

  // -----------------------------------------------------------------------
  // 7. Event-driven pipeline (EventBus → full stack)
  // -----------------------------------------------------------------------
  describe('event-driven full pipeline', () => {
    it('should process order:created event through the full pipeline', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      // Service has the notification
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.type).toBe('order_confirmation');
      expect(notifications[0]?.status).toBe('sent');

      // Email adapter received it
      expect(emailAdapter.getSentEmails()).toHaveLength(1);

      // History recorded it
      expect(historyService.getCount()).toBe(1);
      expect(historyService.getByType('order_confirmation')).toHaveLength(1);
    });

    it('should process order:status-changed event through the full pipeline', async () => {
      await eventBus.emit(makeOrderStatusChangedEvent());

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.type).toBe('order_status_update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');

      // Email adapter received it
      expect(emailAdapter.getSentEmails()).toHaveLength(1);

      // History recorded it
      expect(historyService.getByType('order_status_update')).toHaveLength(1);
    });

    it('should suppress event-triggered notification when preferences disable it', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false } },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      // Notification should be suppressed
      expect(notificationService.getNotificationCount()).toBe(0);
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(historyService.getCount()).toBe(0);
    });

    it('should handle multiple events in sequence correctly', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeOrderStatusChangedEvent());

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0]?.type).toBe('order_confirmation');
      expect(notifications[1]?.type).toBe('order_status_update');

      // Both went through email adapter
      expect(emailAdapter.getSentEmails()).toHaveLength(2);

      // Both logged in history
      expect(historyService.getCount()).toBe(2);
      const logs = historyService.getAll();
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[1]?.type).toBe('order_status_update');
    });
  });

  // -----------------------------------------------------------------------
  // 8. Multi-user isolation
  // -----------------------------------------------------------------------
  describe('multi-user preference isolation', () => {
    it('should respect per-user preferences independently', async () => {
      // user-1: disable email
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false } },
      });
      // user-2: keep defaults (all enabled)

      const result1 = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-1',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Your order',
        channel: 'email',
      });
      const result2 = await notificationService.sendNotification({
        type: 'order_confirmation',
        userId: 'user-2',
        recipient: 'bob@example.com',
        subject: 'Order',
        body: 'Your order',
        channel: 'email',
      });

      expect(result1).toBeNull();
      expect(result2).not.toBeNull();

      // Only one email was actually sent
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(emailAdapter.getSentEmails()[0]?.to).toBe('bob@example.com');
    });
  });
});

